-- ── Brightpearl ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Brightpearl is a cloud-based retail operating system for multichannel retailers and wholesalers, covering inventory management, order management, purchasing, warehousing, CRM, and financial management in one connected platform. Founded in Bristol, UK in 2007 by Chris Tanner and Andrew Mulvenna (originally spun out of their sports retail business, Lush Longboards, as Pearl Software before being renamed Brightpearl in 2010), the company grew into one of the best-known operations platforms for growing ecommerce and wholesale brands. In December 2021, Sage Group plc agreed to acquire the roughly 83 percent of Brightpearl it did not already own for around 299 million pounds (about 340 million dollars total, including its existing 17 percent stake), and the acquisition completed in January 2022. Brightpearl now operates as 'Brightpearl by Sage,' extending Sage's retail and ecommerce financial management proposition, particularly alongside Sage Intacct, while continuing to be sold and supported as a distinct product for product-centric, high-volume retailers and wholesalers rather than being folded into a single unified Sage SKU.$q$, short_description),
  pricing_model = COALESCE($q$Custom enterprise quote (sales-assisted, tiered by order volume)$q$, pricing_model),
  starting_price = COALESCE($q$Pricing is not publicly listed; quotes are based on order volume and modules needed$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$201-500 employees (as part of Sage Group, exact standalone headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Bristol, England, United Kingdom (with a US office in Austin, Texas)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Brightpearl by Sage Review 2026: Retail Operations Platform Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Brightpearl (now Brightpearl by Sage) is a retail operating system for inventory, orders, and multichannel fulfillment. See how it works post-acquisition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Brightpearl is a cloud-based retail operating system built for multichannel retailers and wholesalers that need a single platform to manage inventory, sales orders, purchasing, warehousing, fulfillment, customer relationships, and financials as order volume grows. The company was founded in Bristol, England in 2007 by Chris Tanner and Andrew Mulvenna, who had previously built the software to run their own retail business, a sports equipment brand called Lush Longboards. That internal tool was first sold externally under the name Pearl Software starting in 2008, gained its first outside investment from Eden Ventures, and was renamed Brightpearl in 2010 as the company grew beyond its original retail roots into a broader operations platform. Over the following decade, Brightpearl built a reputation among fast-growing direct-to-consumer and wholesale brands as a 'retail operating system' - a category label the company itself popularized - that connects storefronts, marketplaces, warehouses, and accounting into one real-time view, reducing the manual reconciliation that comes from running separate point solutions for each function. In December 2021, Sage Group plc, the UK-based enterprise software company known for Sage Intacct, Sage 300, and Sage X3, announced it would acquire full ownership of Brightpearl. Sage had already held a minority 17 percent stake in the company; it agreed to pay approximately 299 million pounds (roughly 340 million dollars combined with its existing stake) for the remaining 83 percent. The deal closed in January 2022. At the time of the acquisition, Brightpearl was generating an estimated 27 million dollars in annual revenue, growing at around 50 percent year over year, and the strategic rationale for Sage was to extend its financial management stack deeper into product-centric ecommerce and wholesale businesses, complementing Sage Intacct's accounting core with Brightpearl's inventory, order management, and fulfillment capabilities. Since the acquisition, the product has continued to operate under the brand 'Brightpearl by Sage' rather than being immediately merged into a single unified Sage product, and it is positioned within the Sage portfolio as the retail- and wholesale-specific operations layer that can work alongside Sage's broader financial management tools. For retailers evaluating Brightpearl today, the practical implications of the Sage ownership are twofold: backing from a large, publicly traded software company with substantial resources for security, uptime, and long-term investment, and a sales and pricing motion consistent with Sage's typical enterprise approach - custom quotes scoped to order volume and required modules rather than self-serve, published pricing tiers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '24e9f089-ad76-4e59-9d89-b82d251bd1a3';

