-- ── broot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$broot is a free, open-source terminal file tree navigator written in Rust by developer Denys Seguret (known online as Canop or dystroy). First released in early 2019 and still under active development, broot gives command-line users a fast, visual way to explore directory structures without the overwhelming output of the classic Unix tree command. Instead of dumping a flat listing, broot renders a live, navigable tree view directly in the terminal: any keystroke instantly narrows the view with fuzzy search, and users can jump into directories, preview files, and launch shell commands or editors on selected items without leaving the tree. It respects .gitignore rules by default so build artifacts and dependency folders stay out of the way, includes a git status mode that overlays file changes and branch information onto the tree, and offers a dedicated whale-spotting mode for quickly finding which files or folders are consuming the most disk space. broot is distributed under the MIT license and installs through most major package managers, including Homebrew, Cargo, Pacman, and APT via Debian or Ubuntu packages, and its GitHub repository has accumulated more than 11,000 stars.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (no paid tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$1-10 (independent open-source project maintained primarily by its creator and community contributors)$q$, company_size),
  headquarters = COALESCE($q$Not applicable - open-source project with no corporate headquarters (maintainer based in France)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$broot Review 2026: The Rust Terminal File Tree Navigator Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$broot is a free, open-source Rust tool for navigating directory trees in the terminal. See its features, git integration, disk usage mode, and how to install it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$broot is a free, open-source command-line tool that reinvents how developers and system administrators navigate directory structures in a terminal. It was created by French developer Denys Seguret, who goes by Canop or dystroy in open-source communities, and written in Rust, a systems programming language chosen for its performance and memory safety. Early version history shows broot was already at version 0.5.0 by January 2019 and continuing through versions 0.9 and 0.10 later that year, indicating the project's public life began in late 2018 or very early 2019, making it a mature, multi-year project by 2026 rather than a recent entrant. The core problem broot solves is one every terminal user has run into: the built-in tree command dumps an entire directory structure as a flat, static wall of text that becomes unusable on any reasonably sized project or filesystem. broot instead renders an interactive, scrollable tree directly in the terminal, and it responds to keystrokes in real time, meaning any character typed instantly narrows the visible tree through fuzzy matching rather than requiring a full search term and an enter key press. This non-blocking search design lets users refine or completely change their query mid-search without waiting for a previous search to finish, which is especially useful on very large directory trees where a naive recursive listing would be slow. Beyond navigation, broot functions as a lightweight file manager: from within the tree view, users can copy, move, rename, and delete files and directories, open files in their preferred editor, or launch arbitrary shell commands scoped to the selected file or folder. It automatically honors .gitignore rules, which keeps node_modules, build output, and other generated directories from cluttering the view, and it ships with a git integration mode - triggered with the :gf command to show file statuses, branch name, and change statistics, or :gs to filter the tree down to only the files that git status would report as changed. A separate whale-spotting mode, enabled with the --whale-spotting flag or its -w shortcut, switches the tree into a disk-usage-focused view that computes and displays file sizes, modification dates, and file counts in the background as the user navigates, making it a fast way to hunt down what is eating up disk space without waiting for a slow, blocking scan to complete first. broot is released under the permissive MIT license and is actively packaged for a wide range of platforms: it can be installed via Homebrew on macOS and Linux, via Cargo (Rust's native package manager) on any platform with a Rust toolchain, via Pacman on Arch Linux, and via APT-compatible packages or Snap on Debian and Ubuntu. As an open-source project with no company behind it, broot has no pricing, subscription, or licensing cost of any kind - it is free to use, free to modify under the terms of the MIT license, and its source code and documentation are hosted publicly on GitHub under the Canop/broot repository, which has passed 11,000 stars, reflecting sustained popularity within the terminal power-user and Rust communities.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c227968d-30da-4d0b-9a4e-428bc0305d94';

